import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"42A. Travelling And Relocation","description":"","frontmatter":{"title":"42A. Travelling And Relocation","eba":"Allied Health Professionals 2021-2026","topics":["hours","shift-work","allowances","travel"]},"headers":[],"relativePath":"ebas/allied-health/allowances/42A-travelling-and-relocation.md","filePath":"ebas/allied-health/allowances/42A-travelling-and-relocation.md"}'),r={name:"ebas/allied-health/allowances/42A-travelling-and-relocation.md"};function l(s,e,i,p,h,d){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_42a-travelling-and-relocation" tabindex="-1">42A. Travelling And Relocation <a class="header-anchor" href="#_42a-travelling-and-relocation" aria-label="Permalink to &quot;42A. Travelling And Relocation&quot;">​</a></h1><p>This clause concerns payment only and is not intended to exclude the requirements of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) or 25 (Redundancy and Related Entitlements) or create a new right to be directed to work at another location.</p><p><strong>42A.1</strong> In this clause 42A Base Employment Campus means a Campus of the Employer at which the Employee ordinarily starts and finishes work.</p><p><strong>42A.2</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus during a shift, the Employee will be paid the travel allowance at subclause 41.1. For the avoidance of doubt, the travel will occur within paid time.</p><p><strong>42A.3</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus prior to a shift, the Employee will:</p><p><strong>(a)</strong> be reimbursed for any additional travelling cost to the Employee (where applicable) excluding time spent travelling (which is addressed at subclause</p><p><strong>42A.6</strong> below); and</p><p><strong>(b)</strong> where travel time increases by 15 minutes or greater (to and return) be paid an allowance equal to the Employee&#39;s ordinary rate for the additional time spent when compared to the Employee&#39;s travel time to the Base Employment Campus. Nothing in this subclause 42A.6 prevents an Employer requiring the travel to occur within the rostered shift.</p><p><strong>42A.4</strong> Where an Employee is required by the Employer to permanently relocate from their Base Employment Campus to another Campus as a result of redundancy, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with subclause 25.7 of this Agreement (Relocation).</p><p><strong>42A.5</strong> For the avoidance of doubt, nothing in this clause 42A limits the obligations regarding redundancy contained at <a href="/eba/ebas/allied-health/employment/25-redundancy-and-related-entitlements.html">clause 25</a> of this Agreement.</p><p><strong>42A.6</strong> Where an Employee’s position is required by the Employer to permanently relocate from their Base Employment Campus to another Campus and the Employee’s position is not redundant, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with subclauses 25.7(b) to (f) of this Agreement.</p><p><strong>42A.7</strong> For the avoidance of doubt, where this is a result of a Major Change, the terms of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> will apply, save that the Employer will not be required to take additional steps to mitigate or avert the cost of the relocation.</p><p><strong>42A.8</strong> This clause 42A does not apply to:</p><p><strong>(a)</strong> an Employee whose role goes across campuses;</p><p><strong>(b)</strong> Employees who genuinely choose to work across different campuses and it is not a requirement of the Employer, such as where an Employee elects to pick up an additional shift/s on another Campus on a permanent or ad hoc basis; or</p><p><strong>(c)</strong> Casual Employees.</p>',16)])])}const u=t(r,[["render",l]]);export{m as __pageData,u as default};
